/* ── Core functions ── */
function getLang() { return localStorage.getItem('nflpt-lang') || 'pt'; }

function setLang(l) {
  localStorage.setItem('nflpt-lang', l);
  document.documentElement.setAttribute('lang', l === 'en' ? 'en-US' : 'pt-PT');
  applyTranslations(l);
  updateLangBtns(l);
}

function toggleLang() { setLang(getLang() === 'pt' ? 'en' : 'pt'); }
window.toggleLang = toggleLang;

function applyTranslations(lang) {
  const dict = lang === 'en' ? I18N_EN : I18N_PT;
  const navDict = I18N_NAV[lang] || I18N_NAV.pt;

  /* 1. data-i18n-keyed nav/footer elements */
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if (navDict[key] !== undefined) {
      el.textContent = navDict[key];
    } else if (dict[key] !== undefined) {
      /* preserve child elements — only replace direct text nodes */
      const val = dict[key];
      if (el.children.length === 0) {
        el.textContent = val;
      } else {
        /* replace first text node only */
        for (const node of el.childNodes) {
          if (node.nodeType === 3 && node.textContent.trim()) {
            node.textContent = val;
            break;
          }
        }
      }
    }
  });
}

function updateLangBtns(lang) {
  document.querySelectorAll('.btn-lang').forEach(btn => {
    btn.textContent = lang === 'pt' ? '🌐 EN' : '🌐 PT';
    btn.title = lang === 'pt' ? 'Switch to English' : 'Mudar para Português';
  });
}

/* ── Init on load ── */
window._i18nLoaded = true;
document.addEventListener('DOMContentLoaded', () => {
  const lang = getLang();
  document.documentElement.setAttribute('lang', lang === 'en' ? 'en-US' : 'pt-PT');
  /* Delay to allow nav.js injection to complete */
  setTimeout(() => {
    applyTranslations(lang);
    updateLangBtns(lang);
  }, 60);
});
